import React, { useState, useEffect } from "react";
import { GoogleGenAI } from "@google/genai";

const PG={HOME:"home",TRAINING:"training",WATCH:"watch",BOOK:"book",ABOUT:"about",LIBRARY:"library",FOUNDATION:"foundation",GIVE:"give",PRIVACY:"privacy",TERMS:"terms",DISCLAIMER:"disclaimer"};
const FN=[PG.TRAINING,PG.WATCH,PG.BOOK];

const GS=()=>(<style>{`
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;0,900;1,400&family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400&family=Libre+Baskerville:ital,wght@0,400;0,700;1,400&display=swap');
:root{--bg:#0a0a0a;--bg2:#111;--gold:#c9a84c;--gold-l:#e4cc7a;--gold-d:#a8872e;--cream:#f5f0e8;--cream-m:#d4cfc5;--dim:#7a756b;--muted:#b0aa9e;--serif:'Playfair Display',Georgia,serif;--body:'Libre Baskerville',Georgia,serif;--accent:'Cormorant Garamond',Georgia,serif}
*{box-sizing:border-box;margin:0;padding:0}html{scroll-behavior:smooth}body{background:var(--bg);color:var(--cream);font-family:var(--body);-webkit-font-smoothing:antialiased;font-size:20px}::selection{background:rgba(201,168,76,.3);color:var(--cream)}
@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}.fade-in{opacity:0;animation:fadeUp .7s ease forwards}.d1{animation-delay:.2s}.d2{animation-delay:.4s}.d3{animation-delay:.6s}.d4{animation-delay:.8s}@keyframes spin{to{transform:rotate(360deg)}}
`}</style>);

// ── Atoms ──
const Btn=({children,onClick,large,href})=>{const s={fontFamily:"var(--accent)",fontSize:large?"1.25rem":"1.1rem",fontWeight:600,letterSpacing:".16em",textTransform:"uppercase",color:"var(--bg)",background:"linear-gradient(135deg,var(--gold-l),var(--gold),var(--gold-d))",padding:large?"1.15rem 3.2rem":".75rem 1.8rem",border:"none",cursor:"pointer",transition:"all .35s",display:"inline-block",textDecoration:"none"};return href?<a href={href} target="_blank" rel="noopener noreferrer" style={s}>{children}</a>:<button onClick={onClick} style={s}>{children}</button>};
const SL=({children})=>(<div style={{fontFamily:"var(--accent)",fontSize:"1.05rem",fontWeight:600,letterSpacing:".22em",textTransform:"uppercase",color:"var(--gold-d)",marginBottom:"2rem"}}>{children}</div>);
const Hd=({children,sz="clamp(1.8rem,3.5vw,2.6rem)"})=>(<h2 style={{fontFamily:"var(--serif)",fontSize:sz,fontWeight:700,color:"var(--cream)",lineHeight:1.3,marginBottom:"1.5rem"}}>{children}</h2>);
const Bd=({children,c})=>(<p style={{fontSize:"1.35rem",color:"var(--muted)",marginBottom:"1.5rem",lineHeight:1.75,textAlign:c?"center":"left"}}>{children}</p>);
const CB=({t,d})=>(<div style={{borderLeft:"2px solid var(--gold-d)",padding:"1.5rem 2rem",margin:"1.5rem 0",background:"rgba(201,168,76,.03)"}}><h3 style={{fontFamily:"var(--serif)",fontSize:"1.4rem",color:"var(--gold-l)",marginBottom:".6rem"}}>{t}</h3><p style={{fontSize:"1.2rem",color:"var(--cream-m)",lineHeight:1.65,margin:0}}>{d}</p></div>);
const FI=({t})=>(<div style={{display:"flex",gap:"1rem",padding:".9rem 0",borderBottom:"1px solid rgba(201,168,76,.06)"}}><span style={{color:"var(--gold)",fontSize:"1.2rem",flexShrink:0}}>◆</span><span style={{fontFamily:"var(--accent)",fontSize:"1.2rem",color:"var(--cream-m)",lineHeight:1.55}}>{t}</span></div>);
const RI=({c})=>(<div style={{display:"flex",alignItems:"baseline",gap:"1rem",padding:".75rem 0",borderBottom:"1px solid rgba(201,168,76,.08)",fontSize:"1.25rem"}}><span style={{color:"var(--gold)"}}>✓</span><span style={{textDecoration:"line-through",color:"var(--dim)"}}>{c}</span><span style={{color:"var(--gold)",fontWeight:700,fontSize:"1.1rem",marginLeft:"auto"}}>RESOLVED</span></div>);
const SI=({t})=>(<div style={{background:"var(--bg)",padding:"1.3rem 1.6rem",fontFamily:"var(--accent)",fontSize:"1.25rem",color:"var(--cream-m)",display:"flex",alignItems:"center",gap:".8rem"}}><span style={{color:"var(--gold-d)"}}>—</span>{t}</div>);
const Sec=({children,bg,pad="5rem 0"})=>(<section style={{padding:pad,background:bg||"transparent",borderTop:bg?"1px solid rgba(201,168,76,.1)":"none",borderBottom:bg?"1px solid rgba(201,168,76,.1)":"none"}}><div style={{maxWidth:820,margin:"0 auto",padding:"0 1.5rem"}}>{children}</div></section>);
const VT=({id,h,name})=>(<div style={{background:"var(--bg2)",border:"1px solid rgba(201,168,76,.1)",overflow:"hidden"}}><div style={{position:"relative",width:"100%",paddingBottom:"177.78%"}}><iframe src={`https://player.vimeo.com/video/${id}?h=${h}&badge=0&autopause=0`} style={{position:"absolute",top:0,left:0,width:"100%",height:"100%",border:"none"}} allow="autoplay; fullscreen" allowFullScreen title={name}/></div><div style={{padding:".8rem 1rem",textAlign:"center"}}><span style={{fontFamily:"var(--accent)",fontSize:"1.1rem",color:"var(--gold-d)"}}>{name}</span></div></div>);
const TR=({items,cols=3})=>(<><style>{`@media(max-width:768px){.kf-tr{grid-template-columns:1fr!important}}`}</style><div className="kf-tr" style={{display:"grid",gridTemplateColumns:`repeat(${cols},1fr)`,gap:"1rem"}}>{items.map(i=><VT key={i.name+i.id} {...i}/>)}</div></>);
const BC=({img,title,price,amz})=>(<div style={{background:"var(--bg2)",border:"1px solid rgba(201,168,76,.08)",padding:"1rem",display:"flex",flexDirection:"column",alignItems:"center",textAlign:"center"}}><img src={img} alt={title} style={{width:"100%",maxWidth:170,height:"auto",border:"1px solid rgba(201,168,76,.12)",marginBottom:"1rem"}}/><h3 style={{fontFamily:"var(--serif)",fontSize:"1.1rem",fontWeight:700,color:"var(--cream)",lineHeight:1.3,marginBottom:".5rem",minHeight:"2.6rem"}}>{title}</h3><span style={{fontFamily:"var(--serif)",fontSize:"1.2rem",fontWeight:700,color:"var(--gold)",marginBottom:".8rem"}}>{price}</span><Btn href={amz}>Amazon</Btn></div>);
const Bridge=()=>(<p style={{fontFamily:"var(--accent)",fontSize:"1.05rem",color:"var(--dim)",marginBottom:"2rem",fontStyle:"italic"}}>Some testimonials reference my former name, Matthew David Hurtado.</p>);

// ── Nav ──
const Nav=({pg,sp})=>{const f=FN.includes(pg);const[sc,setSc]=useState(false);const[mo,setMo]=useState(false);useEffect(()=>{const h=()=>setSc(window.scrollY>40);window.addEventListener("scroll",h);return()=>window.removeEventListener("scroll",h)},[]);
const navBg=sc?"rgba(10,10,10,.95)":"rgba(10,10,10,.8)";
return(<>
<nav style={{position:"fixed",top:0,left:0,right:0,zIndex:100,display:"flex",justifyContent:"space-between",alignItems:"center",padding:"1rem 1.5rem",background:navBg,backdropFilter:"blur(12px)",borderBottom:"1px solid rgba(201,168,76,.12)"}}>
  <span onClick={()=>{sp(PG.HOME);setMo(false)}} style={{fontFamily:"var(--accent)",fontSize:"1.4rem",fontWeight:600,color:"var(--cream)",letterSpacing:".08em",cursor:"pointer"}}>Kingley Foundation</span>
  <div style={{display:"flex",alignItems:"center",gap:"1rem"}}>
    <div className="kf-desktop-links" style={{display:"flex",gap:"1.8rem",alignItems:"center"}}>
      {!f&&<>{[["About",PG.ABOUT],["Library",PG.LIBRARY],["Foundation",PG.FOUNDATION]].map(([l,p])=>(<span key={p} onClick={()=>sp(p)} style={{fontFamily:"var(--accent)",fontSize:"1.15rem",color:pg===p?"var(--cream)":"var(--muted)",cursor:"pointer"}}>{l}</span>))}<span onClick={()=>sp(PG.TRAINING)} style={{fontFamily:"var(--accent)",fontSize:"1.1rem",color:"var(--gold-d)",cursor:"pointer"}}>Free Training</span></>}
    </div>
    <button onClick={()=>sp(PG.GIVE)} style={{fontFamily:"var(--accent)",fontSize:"1.05rem",fontWeight:700,letterSpacing:".18em",textTransform:"uppercase",color:"var(--bg)",background:"var(--gold)",padding:".6rem 1.6rem",border:"none",cursor:"pointer"}}>GIVE</button>
    <button onClick={()=>setMo(!mo)} className="kf-hamburger" style={{display:"none",flexDirection:"column",justifyContent:"center",alignItems:"center",gap:"5px",background:"none",border:"none",cursor:"pointer",padding:"4px",width:36,height:36}}>
      <span style={{display:"block",width:22,height:2,background:mo?"var(--gold)":"var(--cream)",transition:"all .25s",transform:mo?"rotate(45deg) translate(5px,5px)":"none"}}/>
      <span style={{display:"block",width:22,height:2,background:mo?"var(--gold)":"var(--cream)",transition:"all .25s",opacity:mo?0:1}}/>
      <span style={{display:"block",width:22,height:2,background:mo?"var(--gold)":"var(--cream)",transition:"all .25s",transform:mo?"rotate(-45deg) translate(5px,-5px)":"none"}}/>
    </button>
  </div>
</nav>
{mo&&<div style={{position:"fixed",top:"60px",left:0,right:0,zIndex:99,background:"rgba(10,10,10,.97)",borderBottom:"1px solid rgba(201,168,76,.15)",display:"flex",flexDirection:"column",padding:"1.5rem 2rem",gap:"0"}}>
  {!f&&<>{[["About",PG.ABOUT],["Library",PG.LIBRARY],["Foundation",PG.FOUNDATION]].map(([l,p])=>(<span key={p} onClick={()=>{sp(p);setMo(false)}} style={{fontFamily:"var(--accent)",fontSize:"1.2rem",color:pg===p?"var(--cream)":"var(--muted)",cursor:"pointer",padding:".75rem 0",borderBottom:"1px solid rgba(201,168,76,.08)",display:"block"}}>{l}</span>))}<span onClick={()=>{sp(PG.TRAINING);setMo(false)}} style={{fontFamily:"var(--accent)",fontSize:"1.15rem",color:"var(--gold-d)",cursor:"pointer",padding:".75rem 0",display:"block"}}>Free Training</span></>}
</div>}
<style>{`@media(max-width:768px){.kf-desktop-links{display:none!important}.kf-hamburger{display:flex!important}}`}</style>
</>);};

