const CryptoRow=({label,addr})=>{const[cp,setCp]=useState(false);return(<div style={{padding:"1.2rem 1.5rem",background:"rgba(201,168,76,.03)",border:"1px solid rgba(201,168,76,.08)",marginBottom:".8rem"}}><div style={{fontFamily:"var(--serif)",fontSize:"1.1rem",fontWeight:700,color:"var(--cream)",marginBottom:".6rem"}}>{label}</div><div style={{display:"flex",alignItems:"center",gap:".8rem",background:"var(--bg)",padding:".8rem 1rem",border:"1px solid rgba(201,168,76,.06)"}}><span style={{fontFamily:"monospace",fontSize:".85rem",color:"var(--muted)",wordBreak:"break-all",flex:1}}>{addr}</span><button onClick={()=>{navigator.clipboard.writeText(addr);setCp(true);setTimeout(()=>setCp(false),2000)}} style={{fontFamily:"var(--accent)",fontSize:".9rem",color:cp?"#4ade80":"var(--gold-d)",background:"none",border:"1px solid rgba(201,168,76,.15)",padding:".4rem .8rem",cursor:"pointer"}}>{cp?"Copied":"Copy"}</button></div></div>)};

const GivePage=({sp})=>{
  const[screen,setScreen]=useState("welcome");
  const[desire,setDesire]=useState("");
  const[med,setMed]=useState(null);
  const[loading,setLoading]=useState(false);

  const generateMed=async()=>{
    setLoading(true);
    try{
      const gemini=new GoogleGenAI({apiKey:import.meta.env.VITE_GEMINI_API_KEY});
      const prompt=`You are a spiritual guide operating in the tradition of Frederick L. Rawson and Biblical covenant law. A person is planting a faith seed and believing God for: "${desire}". Write a response in JSON with these fields: {"meditation":"A 150-word meditation on the spiritual reality of their desire already being fulfilled in Spirit, using Rawson's framework that the spiritual idea has not a single element of error. Reference one specific scripture (NKJV).","lawTitle":"Name of one specific Biblical law or principle that applies","law":"A 100-word explanation of how this law operates mechanically to produce the harvest they are believing for.","rephrasedDesire":"Their desire rephrased in the present tense as already received, in elegant language","multiplier":"hundredfold"} Return ONLY the JSON, no markdown.`;
      const result=await gemini.models.generateContent({model:"gemini-2.5-flash",contents:[{role:"user",parts:[{text:prompt}]}]});
      const t=result.text||"";
      const clean=t.replace(/```json|```/g,"").trim();
      setMed(JSON.parse(clean));
      setScreen("meditation");
    }catch(e){console.error(e);setMed({meditation:"The spiritual reality of your desire is already complete in the Mind of God. What you are believing for has never been absent — it has been waiting for the vessel of your faith to receive it. 'Before they call, I will answer; and while they are still speaking, I will hear.' (Isaiah 65:24 NKJV). The material appearance of lack is the counterfeit. The spiritual fact is wholeness. Rest in this knowing.",lawTitle:"The Law of Sowing and Reaping",law:"'He who sows sparingly will also reap sparingly, and he who sows bountifully will also reap bountifully.' (2 Corinthians 9:6). This is mechanical law — as reliable as gravity. The seed you plant in faith, with cheerfulness, enters the Covenant's operating system and returns multiplied.",rephrasedDesire:desire,multiplier:"hundredfold"});setScreen("meditation")}
    finally{setLoading(false)}
  };

  // WELCOME
  if(screen==="welcome")return(<div style={{maxWidth:820,margin:"0 auto",padding:"7rem 1.5rem 3rem"}}><div style={{textAlign:"center"}} className="fade-in d1"><Hd sz="clamp(2rem,4vw,3rem)">Tithes, Offerings <em style={{color:"var(--gold)",fontStyle:"italic"}}>&amp; Faith Seeds</em></Hd><p style={{fontFamily:"var(--accent)",fontSize:"1.15rem",color:"var(--muted)",marginBottom:"2rem"}}>"You Can't Outgive God."</p></div>
  <div className="fade-in d2" style={{border:"1px solid rgba(201,168,76,.15)",background:"#000",marginBottom:"1.5rem",position:"relative",width:"100%",paddingBottom:"56.25%"}}><video src="https://healswitch.s3.us-east-2.amazonaws.com/the_biblical_laws_of_financial_increase_v1+(1080p).mp4" poster="https://i.imgur.com/JCJktZf.jpg" controls playsInline style={{position:"absolute",top:0,left:0,width:"100%",height:"100%",objectFit:"contain"}}/></div>
  <div style={{textAlign:"center",marginBottom:"2.5rem"}}><Btn large onClick={()=>setScreen("payment")}>Give Now</Btn><p style={{fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--dim)",marginTop:".8rem"}}>PayPal · Stripe · CashApp · BTC · ETH · XRP</p></div>
  <div style={{textAlign:"center",marginBottom:"2.5rem"}}><button onClick={()=>setScreen("harvest")} style={{fontFamily:"var(--accent)",fontSize:"1.1rem",color:"var(--gold-d)",background:"none",border:"2px solid var(--gold-d)",padding:".9rem 2.5rem",cursor:"pointer",letterSpacing:".1em",transition:"all .3s"}} onMouseEnter={e=>{e.target.style.background="var(--gold-d)";e.target.style.color="var(--bg)"}} onMouseLeave={e=>{e.target.style.background="none";e.target.style.color="var(--gold-d)"}}>Prepare My Heart to Receive My Good</button></div>
  <div style={{padding:"2rem",background:"rgba(201,168,76,.03)",border:"1px solid rgba(201,168,76,.08)"}}><p style={{fontFamily:"var(--serif)",fontSize:"1.15rem",fontStyle:"italic",color:"var(--cream-m)",lineHeight:1.6}}>"Bring all the tithes into the storehouse, that there may be food in My house, and try Me now in this," says the LORD of hosts, "If I will not open for you the windows of heaven and pour out for you such blessing that there will not be room enough to receive it."</p><p style={{fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--gold-d)",textAlign:"right",marginTop:"1rem"}}>— Malachi 3:10 NKJV</p></div>
  <div style={{marginTop:"2.5rem",textAlign:"center"}}><img src="https://i.imgur.com/vRXKhjW.jpg" alt="Covenant Frequency" style={{width:"100%",maxWidth:260,border:"1px solid rgba(201,168,76,.12)",marginBottom:"1.5rem"}}/><h3 style={{fontFamily:"var(--serif)",fontSize:"1.3rem",fontWeight:700,color:"var(--cream)",marginBottom:".6rem"}}>Free Gift: The Covenant Frequency</h3><p style={{fontFamily:"var(--accent)",fontSize:"1.05rem",color:"var(--muted)",marginBottom:"1.2rem"}}>The sovereign's manual for activating the ancient laws.</p><Btn href="https://drive.google.com/file/d/1BTl3Wlp3EPrB-hoOjXK1Ollt0yNCCaYs/view?usp=sharing">Download Free</Btn></div>
  </div>);

  // HARVEST
  if(screen==="harvest")return(<div style={{maxWidth:600,margin:"0 auto",padding:"7rem 1.5rem 3rem",textAlign:"center"}} className="fade-in d1"><Hd>Declare Your Harvest</Hd><Bd c>What are you using your faith to believe God for? Be specific. Write it down and make it plain.</Bd><textarea value={desire} onChange={e=>setDesire(e.target.value)} placeholder="e.g., 'Perfect health in my body,' 'Financial abundance to clear all debts,' 'Wisdom to lead my family'..." style={{width:"100%",minHeight:160,padding:"1.2rem",background:"var(--bg)",border:"1px solid rgba(201,168,76,.15)",color:"var(--cream)",fontFamily:"var(--accent)",fontSize:"1.1rem",outline:"none",resize:"vertical",lineHeight:1.6,marginBottom:"1.5rem"}}/><Btn large onClick={generateMed}>Submit</Btn><div style={{marginTop:"1.5rem"}}><button onClick={()=>setScreen("welcome")} style={{fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--dim)",background:"none",border:"none",cursor:"pointer"}}>← Back</button></div></div>);

  // LOADING
  if(loading)return(<div style={{maxWidth:600,margin:"0 auto",padding:"12rem 1.5rem",textAlign:"center"}}><div style={{width:50,height:50,border:"3px solid rgba(201,168,76,.2)",borderTop:"3px solid var(--gold)",borderRadius:"50%",animation:"spin 1s linear infinite",margin:"0 auto 1.5rem"}}></div><style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style><p style={{fontFamily:"var(--accent)",fontSize:"1.15rem",color:"var(--muted)"}}>Preparing your meditation...</p></div>);

  // MEDITATION
  if(screen==="meditation"&&med)return(<div style={{maxWidth:700,margin:"0 auto",padding:"7rem 1.5rem 3rem"}} className="fade-in d1"><div style={{textAlign:"center",marginBottom:"2rem"}}><Hd>A Word of Gnosis</Hd></div><div style={{marginBottom:"2rem"}}><h3 style={{fontFamily:"var(--serif)",fontSize:"1.2rem",color:"var(--gold-l)",marginBottom:"1rem",borderBottom:"1px solid rgba(201,168,76,.1)",paddingBottom:".8rem"}}>Meditation on Reality</h3><p style={{fontSize:"1.15rem",color:"var(--cream-m)",lineHeight:1.7,whiteSpace:"pre-wrap"}}>{med.meditation}</p></div><div style={{marginBottom:"2rem"}}><h3 style={{fontFamily:"var(--serif)",fontSize:"1.2rem",color:"var(--gold-l)",marginBottom:"1rem",borderBottom:"1px solid rgba(201,168,76,.1)",paddingBottom:".8rem"}}>{med.lawTitle}</h3><p style={{fontSize:"1.15rem",color:"var(--cream-m)",lineHeight:1.7,whiteSpace:"pre-wrap"}}>{med.law}</p></div><div style={{textAlign:"center"}}><Btn large onClick={()=>setScreen("declaration")}>Prepare My Declaration</Btn><div style={{marginTop:"1rem"}}><button onClick={()=>setScreen("payment")} style={{fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--dim)",background:"none",border:"none",cursor:"pointer"}}>Skip to giving →</button></div><div style={{marginTop:".5rem"}}><button onClick={()=>setScreen("meditation")||setScreen("harvest")} style={{fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--dim)",background:"none",border:"none",cursor:"pointer"}}>← Back</button></div></div></div>);

  // DECLARATION
  if(screen==="declaration"&&med)return(<div style={{maxWidth:700,margin:"0 auto",padding:"7rem 1.5rem 3rem",textAlign:"center"}} className="fade-in d1"><Hd>Speak Your Faith</Hd><Bd c>Read this declaration aloud. Let the words resonate from your spirit.</Bd><div style={{padding:"2.5rem",background:"rgba(201,168,76,.03)",border:"1px solid rgba(201,168,76,.12)",textAlign:"left",marginBottom:"2rem"}}><p style={{fontFamily:"var(--serif)",fontSize:"1.25rem",fontStyle:"italic",color:"var(--cream)",lineHeight:1.7}}>"I believe that I have already received <strong style={{color:"var(--gold)",fontStyle:"normal"}}>{med.rephrasedDesire}</strong>. Out of the overflow of abundance in Me, I plant this seed with faith and birth supernatural expectation within. I am resting on Divine Law now. I release this money freely and God returns it to me exceedingly — multiplied a <strong style={{color:"var(--gold)",fontStyle:"normal"}}>{med.multiplier}</strong>, in Jesus Christ's name. It is done."</p></div><Bd c>Your heart is now ready to sow your faith-seed.</Bd><Btn large onClick={()=>setScreen("payment")}>Proceed to Give</Btn><div style={{marginTop:"1rem"}}><button onClick={()=>setScreen("meditation")} style={{fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--dim)",background:"none",border:"none",cursor:"pointer"}}>← Back</button></div></div>);

  // PAYMENT
  if(screen==="payment")return(<div style={{maxWidth:600,margin:"0 auto",padding:"7rem 1.5rem 3rem"}} className="fade-in d1"><div style={{textAlign:"center",marginBottom:"2rem"}}><Hd>Choose Your Method</Hd><p style={{fontFamily:"var(--accent)",fontSize:"1.1rem",color:"var(--muted)",fontStyle:"italic"}}>"You Can't Outgive God."</p></div>{[["PayPal",PAY.PAYPAL],["Stripe — Credit/Debit, Klarna",PAY.STRIPE],["Cash App",PAY.CASHAPP]].map(([l,u])=>(<a key={l} href={u} target="_blank" rel="noopener noreferrer" style={{display:"flex",alignItems:"center",padding:"1.2rem 1.5rem",background:"rgba(201,168,76,.03)",border:"1px solid rgba(201,168,76,.08)",marginBottom:".8rem",textDecoration:"none",transition:"background .3s"}} onMouseEnter={e=>e.currentTarget.style.background="rgba(201,168,76,.08)"} onMouseLeave={e=>e.currentTarget.style.background="rgba(201,168,76,.03)"}><span style={{fontFamily:"var(--serif)",fontSize:"1.15rem",fontWeight:700,color:"var(--cream)"}}>{l}</span><span style={{marginLeft:"auto",fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--gold-d)"}}>→</span></a>))}<div style={{borderTop:"1px solid rgba(201,168,76,.1)",margin:"1.5rem 0",paddingTop:"1.5rem"}}><p style={{fontFamily:"var(--accent)",fontSize:"1rem",fontWeight:600,color:"var(--gold-d)",letterSpacing:".15em",marginBottom:"1rem"}}>CRYPTOCURRENCY</p><CryptoRow label="Bitcoin (BTC)" addr={CRYPTO.BTC}/><CryptoRow label="Ethereum (ETH) & Stablecoins" addr={CRYPTO.ETH}/><CryptoRow label="XRP" addr={CRYPTO.XRP}/></div><div style={{marginTop:"2rem",textAlign:"center"}}><button onClick={()=>setScreen("welcome")} style={{fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--dim)",background:"none",border:"none",cursor:"pointer"}}>← Back</button></div>
  <div style={{marginTop:"2.5rem",padding:"1.5rem",background:"var(--bg2)",border:"1px solid rgba(201,168,76,.06)"}}><details><summary style={{fontFamily:"var(--accent)",fontSize:"1rem",color:"var(--cream-m)",cursor:"pointer"}}>Important Disclaimers</summary><div style={{marginTop:"1rem",fontFamily:"var(--accent)",fontSize:".95rem",color:"var(--dim)",lineHeight:1.6}}><p style={{marginBottom:".8rem"}}>All materials presented on MalcolmKingley.Org are offered for spiritual exploration by the Kingley Foundation, a 508(c)(1)(a) organization. Nothing herein constitutes medical, legal, financial, or professional advice.</p><p style={{marginBottom:".8rem"}}>Participation is voluntary. Donations are gifts of support to our private spiritual ministry. They do not constitute purchase of services nor create any guarantee of outcome.</p><p>By engaging with this site or making a donation, you acknowledge that all content exists within the realm of spiritual belief and you accept full responsibility for your own choices.</p></div></details></div></div>);

  return null;
};

